import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Limiting the buffer size to prevent buffer overflow
        int bufferSize = Math.min(input.length(), 10);

        // Creating a fixed size array with a capacity of bufferSize
        char[] buffer = new char[bufferSize];

        // Copying user input into the fixed size array with bounds checking
        for (int i = 0; i < bufferSize; i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Input copied safely into buffer.");
    }
}

